output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select the Pelvic CT Volume",
      "simple": "Choose the Pelvic Volume from the Input CT Volume dropdown.",
      "detailed": "This step selects the CT scan that contains the pelvic anatomy. The pelvic volume is the primary dataset for all subsequent segmentation and planning. Select it from the dropdown list to proceed."
    },
    {
      "step_id": "cb_step_2",
      "title": "Run Pelvis Segmentation",
      "simple": "Click the Run Step 1: Segment Pelvis button to start automated pelvic bone segmentation.",
      "detailed": "This step automatically segments the pelvic bones from the CT volume using the extension's algorithm. The resulting segmentation identifies the intact pelvic bone structures and serves as the anatomical reference for fracture analysis. Click the button to execute the segmentation."
    },
    {
      "step_id": "cb_step_3",
      "title": "Run Fracture Segmentation",
      "simple": "Click the Run Step 2: Segment Fractures button to identify and separate fracture fragments.",
      "detailed": "This step automatically segments the individual fracture fragments from the pelvic volume. Each fragment is separated into distinct segments, enabling you to visualize and manipulate them independently during reduction planning. Click the button to proceed."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Fragments from Planning",
      "simple": "Untick any fracture fragments you wish to exclude from the planning process.",
      "detailed": "Some fragments may be irrelevant for surgical fixation (e.g., small, non-displaced fragments). By excluding them, you simplify the reduction plan and focus only on clinically significant fragments. Uncheck the boxes next to the fragments you want to exclude, then click Done."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the Run Step 3: Generate Template button to create an initial reduction template.",
      "detailed": "This step uses the segmented pelvis and fracture fragments to generate a template that approximates the anatomical alignment of the pelvis. The template serves as a starting point for fracture reduction. Click the button to create the template."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fractures",
      "simple": "Click the Run Step 4: Register _Reduce button to align and reduce the fracture fragments to the template.",
      "detailed": "This step performs automated registration of the fracture fragments to the template, effectively reducing the fracture by aligning the fragments to their anatomical positions. The result is a reduction of the pelvic ring. Click the button to execute the reduction."
    },
    {
      "step_id": "cb_step_7",
      "title": "Manual Adjustment Needed?",
      "simple": "Tick the 'Manually adjust a fragment' checkbox if you need to fine-tune fragment positions, otherwise skip to step 10.",
      "detailed": "After automated reduction, some fragments may still need fine-tuning for optimal alignment. Enabling manual adjustment lets you reposition individual fragments using the 3D view. If the reduction looks satisfactory, proceed directly to the next step. Choose Yes to adjust, No to skip."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment to Adjust",
      "simple": "Choose the fragment you want to adjust from the 'Fragment' selection box.",
      "detailed": "If you need to manually adjust a specific fragment, select it from the dropdown list. This isolates the fragment so you can modify its position and rotation independently. Click Done after selecting."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position",
      "simple": "Use the 3D view to manually reposition and rotate the selected fragment.",
      "detailed": "For optimal anatomical alignment, you can fine-tune the position and rotation of the selected fragment. Drag the manipulator handles in the 3D view to translate and rotate the fragment until it fits properly with adjacent bone surfaces. Then click Done."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Manual Adjustments",
      "simple": "Click the 'Apply adjustments' button to commit your manual fragment changes.",
      "detailed": "This step applies the manual position and rotation changes you made to the selected fragment, updating the reduction result. Click the button to finalize the adjustments."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Trajectories",
      "simple": "Click the 'Run Step 5: Plan Screws' button to automatically generate screw trajectories for fixation.",
      "detailed": "This step analyzes the reduced pelvis and fracture configuration to propose optimal screw trajectories for surgical fixation. The system generates screw paths that avoid critical structures and ensure stable fixation. Click the button to create the screw plan."
    },
    {
      "step_id": "cb_step_12",
      "title": "Edit Screw Trajectories?",
      "simple": "Tick the 'Edit Screw trajectories' checkbox if you need to manually adjust the screw paths, otherwise the plan is complete.",
      "detailed": "The automatically generated screw trajectories may need refinement based on patient-specific anatomy or surgeon preference. Enabling editing lets you modify the position and orientation of each screw. If the plan looks good, you can stop here. Choose Yes to edit, No to finish."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the 3D view to manually reposition and reorient the screw trajectories.",
      "detailed": "Fine-tune each screw's entry point, direction, and depth to ensure safe passage through bone corridors while avoiding neurovascular structures and joints. Drag the manipulator handles to adjust. Then click Done."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws from Edited Lines",
      "simple": "Click the 'Regenerate screw from edited lines' button to update the screw models based on your manual edits.",
      "detailed": "After adjusting the trajectory lines manually, this step regenerates the corresponding screw models (cylinders) to match the edited paths. Click the button to refresh the screw visualization."
    },
    {
      "step_id": "cb_step_15",
      "title": "Disable Screw Editing",
      "simple": "Untick the 'Edit Screw trajectories' checkbox to exit editing mode.",
      "detailed": "Once you have finished adjusting the screw trajectories, deselect this checkbox to lock the final screw plan. This confirms your edits and prevents accidental changes. Then click Done."
    }
  ]
}
